#include<bits/stdc++.h>
using namespace std;

const int N = 1e4 + 5;
const int M = 5e5 + 5;

int n, m, s;

int dis[N], cnt[N];
bool vis[N];

struct Edge
{
    int v, w;
};
vector<Edge> e[N];

bool SPFA()
{
    queue<int> q;
    memset(dis, 0x3f, sizeof dis);
    memset(cnt, 0, sizeof dis);
    memset(vis, 0, sizeof dis);
    dis[s] = 0, vis[s] = 1;
    q.push(s);
    while(!q.empty())
    {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for(auto [v, w] : e[u])
        {
            if(dis[v] > dis[u] + w)
            {
                dis[v] = dis[u] + w;
                cnt[v] = cnt[u] + 1;
                if(!vis[v]) q.push(v), vis[v] = 1;
                if(cnt[v] >= n) return 1;
            }
        }
    }
    return 0;
}

int main()
{
    cin.tie(0) -> sync_with_stdio(0);
    int t;
    cin >> t;
    while(t--)
    {
        cin >> n >> m;
        for(int i = 1; i <= n; i++)
            e[i].clear();
        s = 1;
        for(int i = 1; i <= m; i++)
        {
            int u, v, w;
            cin >> u >> v >> w;
            e[u].push_back({v, w});
            if(w >= 0) e[v].push_back({u, w});
        }
        if(SPFA()) cout << "YES\n";
        else cout << "NO\n";
    }
    return 0;
}
